[DataContractAttribute]
public class KJP_SM_DelivaeryPackageReportContract
{
    private str query, menuItemName;

   
}

Method.Source:
/// <summary>
/// Parm method for storing/retriving  the query
/// </summary>
/// <param name = "_query">Query</param>
/// <returns>String query</returns>
[DataMemberAttribute,
AifQueryTypeAttribute('_query', '')]
public str parmQuery(str _query = query)
{
    query = _query;
    return query;
}

    /// <summary>
    /// For determination report to be executed
    /// </summary>
    /// <param name = "_menuItemName"> Menu Item Name</param>
    /// <returns>Menu Item Name</returns>
    [DataMemberAttribute]
    
    public str parmMenuItemName(str _menuItemName = menuItemName)
    {
        menuItemName = _menuItemName;
        return menuItemName;

    }

/// <summary>
/// Sets and encodes a given query as a base 64 encoded string.
/// </summary>
/// <param name = "_query">The query to be encoded as a base 64 encoded string.</param>
public void setQuery(Query _query)
{
    query = SysOperationHelper::base64Encode(_query.pack());
}
